import{_ as a,o as l,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"155. Meal Allowances","description":"","frontmatter":{"title":"155. Meal Allowances","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/155-meal-allowances.md","filePath":"ebas/mental-health/support-services/preliminary/155-meal-allowances.md"}'),t={name:"ebas/mental-health/support-services/preliminary/155-meal-allowances.md"};function s(n,e,i,h,p,c){return l(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_155-meal-allowances" tabindex="-1">155. Meal Allowances <a class="header-anchor" href="#_155-meal-allowances" aria-label="Permalink to &quot;155. Meal Allowances&quot;">​</a></h1><p><strong>155.1</strong> Where an Employee is required to work overtime Monday to Friday (inclusive) for more than one hour after the usual finish time, or in the case of shift workers when the overtime exceeds one hour, or on a Saturday/Sunday for more than 5 hours, the Employer shall either supply the Employee with an adequate meal or pay a meal allowance.</p><p><strong>155.2</strong> Where such overtime exceeds 4 hours Monday to Friday (inclusive), or 9 hours on a Saturday/Sunday, the Employer shall either supply the Employee with a further adequate meal or pay a further meal allowance.</p><p><strong>155.3</strong> The provisions of clause 155.1 and clause 155.2 shall not apply where the Employee could reasonably return home for a meal within the period allowed.</p><p><strong>155.4</strong> The meal allowances payable over the life of this Agreement are set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>155.5</strong> Claims for payment of an overtime meal allowance will be processed in the next ordinary pay.</p>',6)])])}const d=a(t,[["render",s]]);export{u as __pageData,d as default};
